package arrays.praticando.aprendendo;import java.util.Scanner;public class ArraysNoJava03 {    public static void main(String[] args) {        String[] nomes = new String[3];        Scanner inputName = new Scanner(System.in);        for (int i = 0; i < nomes.length; i++) {            System.out.println("Qual o nome do ninja: ");            String nomeNinja = inputName.nextLine();            nomes[i] = nomeNinja;        }        for (int c = 0; c < nomes.length; c++) {            System.out.println(nomes[c]);        }    }}